    +'<div style="color:#f59e0b;font-size:18px;font-weight:700;margin-bottom:14px">&#9888; Meridian &#8212; Script Load Error</div>'
    +'<div style="color:#f87171;font-size:13px;margin-bottom:16px">Failed to load: <b>'+name+'</b></div>'
