          div({className:'set-sec-t'},'AI & Integrations'),
          div({className:'set-note'},'Anthropic API key enables AI Lookup in Backtest and Anomaly panels. Stored locally in your browser.'),
          div({className:'set-row'},
            div({className:'set-lbl'},'Anthropic API Key',h('a',{href:'https://console.anthropic.com',target:'_blank',style:{fontSize:'9px',color:'#818cf8',marginLeft:6}},'Get key ‚Üí')),
            inp({className:'set-inp',type:'password',defaultValue:(()=>{try{return localStorage.getItem('mf_anthropic_key')||'';}catch{return '';}})(),placeholder:'sk-ant-‚Ä¶',onBlur:e=>{try{if(e.target.value.trim())localStorage.setItem('mf_anthropic_key',e.target.value.trim());else localStorage.removeItem('mf_anthropic_key');}catch{}},style:{fontFamily:'var(--mono)',fontSize:'11px'}})
          )
