      div({style:{marginTop:6,fontSize:'9px',color:ageClr}},
        '‚óè Data: '+( latestLab?latestLab.toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'})+' ('+dataAge+'d ago)':'Not loaded'))
